const item = $input.first();
const attachments = item.json.attachments || [];
const pdf = attachments.find(a =>
  a.mimeType === 'application/pdf' ||
  (a.name || '').toLowerCase().endsWith('.pdf')
);
if (!pdf) throw new Error('No PDF attachment found. Please attach an AU result PDF.');
return [{
  json: {
    threadId:     item.json.threadId,
    messageId:    item.json.id,
    senderEmail:  item.json.from,
    senderName:  (item.json.from || '').split('<')[0].trim() || 'Faculty',
    emailSubject: (item.json.subject || '').toLowerCase().trim(),
    emailBody:    (item.json.text || '').toLowerCase().trim(),
    attachmentName: pdf.name || 'result.pdf',
  },
  binary: { pdf: item.binary['attachment_0'] }
}];

const txt  = JSON.parse($input.first().json.stdout);
const meta = $('Extract PDF Attachment').first().json;
return [{ json: { ...meta, pdfText: txt.text } }];

