parameters.jsCode:
const meta = $('Merge Text + Email Metadata').first().json;
const raw  = $input.first().json;

const text = (meta.emailSubject + ' ' + meta.emailBody).toLowerCase();

// ── Semester detection ─────────────────────────────────────────────────────
const semMatch =
  text.match(/\bsem(?:ester)?\s*(\d)\b/) ||
  text.match(/\b(\d)(?:st|nd|rd|th)?\s*sem(?:ester)?\b/) ||
  text.match(/\bs(\d)\b/);
const targetSem = semMatch ? parseInt(semMatch[1]) : null;

// ── Intent detection ───────────────────────────────────────────────────────
let intent = 'ALL';
const rules = [
  { keys: ['score card','scorecard','rank list','marks','rank list'], intent: 'SCORECARD' },
  { keys: ['subject wise','subject-wise','subjectwise','per subject'], intent: 'SUBJECT' },
  { keys: ['statistics','stats','pass fail','pass percentage','ratio','grade distribution'], intent: 'STATS' },
  { keys: ['insight','recommend','ai analysis','performance report','suggestions'], intent: 'INSIGHTS' },
  { keys: ['arrear','backlog','failed','who failed','reappear','outstanding'], intent: 'ARREAR' },
  { keys: ['full analysis','all report','all pdf','complete analysis','do result analysis',
           'analyse this','analyze this','result analysis','full report'], intent: 'ALL' },
];
for (const rule of rules) {
  if (rule.keys.some(k => text.includes(k))) { intent = rule.intent; break; }
}

const PDF_MAP = {
  ALL:       [1,2,3,4,5],
  SCORECARD: [1],
  ARREAR:    [2],
  SUBJECT:   [3],
  STATS:     [4],
  INSIGHTS:  [5],
};
const pdfsToRun   = PDF_MAP[intent] || [1,2,3,4,5];
const needsInsight = pdfsToRun.includes(5);

// ── Parse Gemini response ──────────────────────────────────────────────────
let txt = raw.candidates[0].content.parts[0].text
  .replace(/```json/gi,'').replace(/```/g,'').trim();
const parsed = JSON.parse(txt);
const INST = parsed.institution;
const allStudents = parsed.students || [];

return [{ json: {
  ...meta,
  INST,
  allStudents,
  intent,
  targetSem,
  pdfsToRun,
  needsInsight,
  semLabel: targetSem ? `Semester ${targetSem}` : 'All Semesters',
} }];

const d = $input.first().json;

const GP = {
  'O':10,'A+':9,'A':8,'B+':7,'B':6,'C':5,
  'U':0,'UA':0,'SA':0,'RA':0,'W':0
};
const SUBJECTS = {
  'AL3501':['Foundations of Artificial Intelligence',4,'Theory'],
  'AL3502':['Machine Learning Techniques',4,'Theory'],
  'CB3491':['Cryptography and Blockchain Technology',3,'Elective'],
  'CCS375':['Natural Language Processing',3,'Prof. Elective III'],
  'CCW331':['Competitive Coding Workshop',2,'Workshop/Lab'],
  'CS3551':['Distributed Computing',4,'Theory'],
  'MX3084':['Open Elective III',3,'Open Elective'],
  'NM1120':['Non-Major Elective II',2,'Non-Major'],
};
const GRADE_LABELS = {
  'O':  ['Outstanding','91-100','Pass'],
  'A+': ['Excellent','81-90','Pass'],
  'A':  ['Very Good','71-80','Pass'],
  'B+': ['Good','61-70','Pass'],
  'B':  ['Average','51-60','Pass'],
  'C':  ['Satisfactory','50','Pass'],
  'U':  ['Reappear','<50','Fail'],
  'SA': ['Shortage Attend.','-','Fail'],
  'UA': ['Absent','-','Fail'],
};

// Apply semester filter
const filtered = d.targetSem
  ? d.allStudents.filter(s => s.semester === d.targetSem)
  : d.allStudents;

if (filtered.length === 0) {
  const available = [...new Set(d.allStudents.map(s => s.semester))].sort().join(', ');
  throw new Error(
    `No students found for ${d.semLabel}. ` +
    `PDF contains semesters: ${available}. ` +
    `Please re-send with a valid semester number.`
  );
}

const isFail    = g => ['U','UA','SA','RA','W'].includes(g);
const numSubs   = s => Object.keys(s.grades || {}).length || 8;
const totalGP   = g => Object.values(g).reduce((s,v) => s + (GP[v]||0), 0);
const calcGPA   = s => Math.round(totalGP(s.grades) / numSubs(s) * 100) / 100;
const getArr    = g => Object.entries(g)
  .filter(([,v]) => isFail(v))
  .map(([code,grade]) => ({ code, grade, subjectName: SUBJECTS[code]?.[0] || code }));

const enriched = filtered.map(s => ({
  ...s,
  totalGP:  totalGP(s.grades),
  gpa:      calcGPA(s),
  arrears:  getArr(s.grades),
  allClear: !Object.values(s.grades).some(isFail),
})).sort((a,b) => b.gpa - a.gpa);

let rank = 1;
enriched.forEach((s,i) => {
  if (i > 0 && enriched[i].gpa < enriched[i-1].gpa) rank = i+1;
  s.rank = rank;
  s.sno  = i+1;
});

const arrearStudents = enriched
  .filter(s => !s.allClear)
  .sort((a,b) => b.arrears.length - a.arrears.length);

const allCodes = [...new Set(filtered.flatMap(s => Object.keys(s.grades || {})))];
const subjectWiseFails = {};
allCodes.forEach(code => {
  const failed   = enriched.filter(s => isFail(s.grades[code]));
  const appeared = enriched.filter(s => s.grades[code]).length;
  subjectWiseFails[code] = {
    subjectName: SUBJECTS[code]?.[0] || code,
    credits:     SUBJECTS[code]?.[1] || 3,
    type:        SUBJECTS[code]?.[2] || 'Theory',
    appeared,
    passed:      appeared - failed.length,
    failedCount: failed.length,
    passRate:    appeared > 0 ? Math.round((appeared-failed.length)/appeared*1000)/10 : 100,
    failedStudents: failed.map(s => ({ regNo:s.regNo, name:s.name, grade:s.grades[code] })),
  };
});

const total    = enriched.length;
const allClear = enriched.filter(s => s.allClear).length;
const totArr   = arrearStudents.reduce((s,st) => s + st.arrears.length, 0);
const avgGPA   = total > 0 ? Math.round(enriched.reduce((s,st) => s+st.gpa, 0)/total*100)/100 : 0;
const gf = {};
enriched.forEach(s => Object.values(s.grades).forEach(g => { gf[g]=(gf[g]||0)+1; }));
const worst = Object.entries(subjectWiseFails).sort((a,b) => b[1].failedCount - a[1].failedCount)[0];

const insightPrompt = d.needsInsight
  ? `Write a formal 3-paragraph HOD report for ${d.INST.instName}.\n` +
    `Branch: ${d.INST.branch}, ${d.semLabel}, ${d.INST.regulation} Regulation.\n` +
    `Total students: ${total}, All clear: ${allClear} (${Math.round(allClear/total*100)}%).\n` +
    `Most failed subject: ${worst?.[0]} — ${worst?.[1]?.subjectName} (${worst?.[1]?.failedCount} failures).\n` +
    `Class GPA average: ${avgGPA}/10. Grade distribution: ${JSON.stringify(gf)}.\n` +
    `Paragraph 1: overall batch performance. Paragraph 2: critical subjects needing remedial classes. Paragraph 3: actionable recommendations.\n` +
    `Formal academic English only. No bullet points.`
  : null;

return [{ json: {
  ...d,
  students:        enriched,
  arrearStudents,
  subjectWiseFails,
  statistics: {
    total, allClear,
    passPercentage: Math.round(allClear/total*1000)/10,
    withArrears:    total - allClear,
    totalArrearCount: totArr,
    avgGPA,
    maxGPA: enriched.length ? Math.max(...enriched.map(s=>s.gpa)) : 0,
    minGPA: enriched.length ? Math.min(...enriched.map(s=>s.gpa)) : 0,
    gradeFrequency: gf,
  },
  GP,
  SUBJECTS,
  GRADE_LABELS,
  insightPrompt,
} }];

// Merge insight text into main data
// Works whether insight was generated or not
const d = $('Structure Data + Semester Filter').first().json;
let insightText = '';
try {
  const ins = $input.first().json;
  if (ins.candidates) {
    insightText = ins.candidates[0].content.parts[0].text;
  } else {
    insightText = 'Insight generation skipped for this report type.';
  }
} catch(e) {
  insightText = 'Insight not requested for this report type.';
}
return [{ json: { ...d, insightText } }];

const d = $('Merge Insight Into Data').first().json;

const intentLabels = {
  ALL:       'Full Result Analysis (all 5 reports)',
  SCORECARD: 'Score Card & Rank List',
  ARREAR:    'Arrear Analysis Report',
  SUBJECT:   'Subject-wise Arrear Report',
  STATS:     'Statistics & Pass/Fail Analysis',
  INSIGHTS:  'AI Insights & Recommendations',
};
const reportName = intentLabels[d.intent] || 'Result Analysis';
const semNote = d.semLabel !== 'All Semesters' ? ` — ${d.semLabel}` : '';

const pdfFiles = [];
if (d.pdfsToRun.includes(1)) pdfFiles.push('1. Score Card & Rank List');
if (d.pdfsToRun.includes(2)) pdfFiles.push('2. Arrear Analysis');
if (d.pdfsToRun.includes(3)) pdfFiles.push('3. Subject-wise Arrear Report');
if (d.pdfsToRun.includes(4)) pdfFiles.push('4. Statistics & Grade Distribution');
if (d.pdfsToRun.includes(5)) pdfFiles.push('5. AI Insights & Recommendations');

const emailBody =
  `Dear ${d.senderName},\n\n` +
  `Please find attached: ${reportName}${semNote}\n\n` +
  `Institution : ${d.INST.instName || ''}\n` +
  `Branch      : ${d.INST.branch || ''}\n` +
  `Semester    : ${d.semLabel}\n` +
  `Regulation  : ${d.INST.regulation || ''}\n\n` +
  `Files attached:\n${pdfFiles.join('\n')}\n\n` +
  `Generated via Result Analyser — n8n + Gemini 2.0 Flash.`;

return [{ json: { ...d, emailBody } }];
